class Solution:
    def maxProduct(self, nums, k, limit):
        n = len(nums)
        best = -1
        for mask in range(1, 1 << n):
            chosen = [nums[i] for i in range(n) if mask & (1 << i)]
            alt = 0
            for idx, v in enumerate(chosen):
                alt += v if idx % 2 == 0 else -v
            if alt != k:
                continue
            prod = 1
            for v in chosen:
                prod *= v
            if prod <= limit and prod > best:
                best = prod
        return best

