class Solution:
    def maxProduct(self, nums, k, limit):
        def scale_cap(mask, x, lim):
            res = 0
            m = mask
            while m:
                low = m & (-m)
                p = low.bit_length() - 1
                m ^= low
                np = p * x
                if np <= lim:
                    res |= (1 << np)
                else:
                    break
            return res
        finite = [dict(), dict()]
        over = [set(), set()]
        for x in nums:
            nfinite = [d.copy() for d in finite]
            nover = [s.copy() for s in over]
            for par in range(2):
                npar = 1 - par
                for alt, mask in finite[par].items():
                    if mask == 0:
                        continue
                    nalt = alt + x if par == 0 else alt - x
                    if x == 0:
                        nfinite[npar][nalt] = nfinite[npar].get(nalt, 0) | 1
                    elif x == 1:
                        nfinite[npar][nalt] = nfinite[npar].get(nalt, 0) | mask
                    else:
                        scaled = scale_cap(mask, x, limit)
                        if scaled:
                            nfinite[npar][nalt] = nfinite[npar].get(nalt, 0) | scaled
                        top = mask.bit_length() - 1
                        if top * x > limit:
                            nover[npar].add(nalt)
                for alt in over[par]:
                    nalt = alt + x if par == 0 else alt - x
                    if x == 0:
                        nfinite[npar][nalt] = nfinite[npar].get(nalt, 0) | 1
                    else:
                        nover[npar].add(nalt)
            if x == 0:
                nfinite[1][0] = nfinite[1].get(0, 0) | 1
            elif x <= limit:
                nfinite[1][x] = nfinite[1].get(x, 0) | (1 << x)
            else:
                nover[1].add(x)
            finite = nfinite
            over = nover
        best = -1
        for par in range(2):
            mask = finite[par].get(k, 0)
            if mask:
                cand = mask.bit_length() - 1
                if cand > best:
                    best = cand
        return best

