var maxProduct = function(nums, k, limit) {
    let finite = [new Map(), new Map()];
    let over = [new Set(), new Set()];
    for (const x of nums) {
        const nfinite = [new Map(finite[0]), new Map(finite[1])];
        const nover = [new Set(over[0]), new Set(over[1])];
        const cloned = [new Set(), new Set()];
        function ensureSet(par, alt) {
            let s = nfinite[par].get(alt);
            if (s === undefined) {
                s = new Set();
                nfinite[par].set(alt, s);
                cloned[par].add(alt);
            } else if (!cloned[par].has(alt)) {
                s = new Set(s);
                nfinite[par].set(alt, s);
                cloned[par].add(alt);
            }
            return s;
        }
        for (let par = 0; par < 2; par++) {
            const npar = 1 - par;
            for (const [alt, set] of finite[par]) {
                if (set.size === 0) continue;
                const nalt = par === 0 ? alt + x : alt - x;
                if (x === 0) {
                    ensureSet(npar, nalt).add(0);
                } else if (x === 1) {
                    const s = ensureSet(npar, nalt);
                    for (const v of set) s.add(v);
                } else {
                    let top = -1;
                    let s = null;
                    for (const v of set) {
                        if (v > top) top = v;
                        const nv = v * x;
                        if (nv <= limit) {
                            if (s === null) s = ensureSet(npar, nalt);
                            s.add(nv);
                        }
                    }
                    if (top * x > limit) nover[npar].add(nalt);
                }
            }
            for (const alt of over[par]) {
                const nalt = par === 0 ? alt + x : alt - x;
                if (x === 0) {
                    ensureSet(npar, nalt).add(0);
                } else {
                    nover[npar].add(nalt);
                }
            }
        }
        if (x === 0) {
            ensureSet(1, 0).add(0);
        } else if (x <= limit) {
            ensureSet(1, x).add(x);
        } else {
            nover[1].add(x);
        }
        finite = nfinite;
        over = nover;
    }
    let best = -1;
    for (let par = 0; par < 2; par++) {
        const set = finite[par].get(k);
        if (set) {
            for (const v of set) if (v > best) best = v;
        }
    }
    return best;
};
